from itertools import islice
from heapq import heappop, heappush
from sympy import factorint, prevprime, nextprime
def A386526_gen(): # generator of terms
    def is_squarefree(n): return max(factorint(n).values(),default=1)<=1
    h, hset = [1], {1}
    while True:
        m = heappop(h)
        if not (is_squarefree(m-1) or is_squarefree(m+1)):
            yield m
        ps = factorint(m)
        for p in ps:
            if p == 2 or ps[prevprime(p)]>ps[p]:
                mp = m*p
                if mp not in hset:
                    heappush(h,mp)
                    hset.add(mp)
        mp = m*nextprime(max(ps.keys(),default=1))
        if mp not in hset:
            heappush(h,mp)
            hset.add(mp)
A386526_list = list(islice(A386526_gen(),40)) # _Chai Wah Wu_, Mar 25 2026

